option.value:
:root {
  --color-black: #020000;
  --color-orange: #E95B00;
  --color-dark-gold: #E17D10;
  --color-gold: #F6B637;
  --color-light-gold: #FFD54C;
  --color-off-white: #FAF9F7;
  --color-muted: #695e58;

  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  color: var(--color-black);
  background: var(--color-off-white);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
}

* { box-sizing: border-box; }
body {
  margin: 0;
  min-width: 320px;
  background:
    linear-gradient(135deg, rgba(255, 122, 89, 0.12), rgba(31, 122, 140, 0.1) 42%, rgba(255, 250, 246, 0) 72%),
    #fffaf6;
}
a { color: inherit; }
button, input, textarea, select { font: inherit; }

.topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 18px;
  background: rgba(255, 250, 246, 0.88);
  backdrop-filter: blur(14px);
  border-bottom: 1px solid rgba(96, 76, 64, 0.12);
  position: sticky;
  top: 0;
  z-index: 10;
}

.brand {
  text-decoration: none;
  font-weight: 800;
  font-size: 19px;
  letter-spacing: 0;
}

nav {
  display: flex;
  gap: 8px;
}

nav a {
  text-decoration: none;
  font-weight: 600;
  font-size: 14px;
  padding: 8px 10px;
  border-radius: 999px;
  color: #62564f;
}

nav a.router-link-active {
  background: #181614;
  color: #fff;
}

.button-link {
  font-weight: 600;
  font-size: 14px;
  padding: 8px 10px;
  border-radius: 999px;
  background: #111;
  color: white;
  text-decoration: none;
  border: none;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
}

.button-link:hover {
  opacity: 0.9;
}

.logout-btn {
  padding: 8px 10px;
}

.container {
  max-width: 860px;
  margin: 0 auto;
  padding: 28px 16px 64px;
}

.hero {
  margin-bottom: 22px;
}

.hero h1 {
  margin: 0 0 8px;
  font-size: 40px;
  line-height: 0.98;
  max-width: 680px;
}

.hero p {
  margin: 0;
  color: #695e58;
  font-size: 17px;
  line-height: 1.45;
  max-width: 620px;
}

.app-hero {
  padding: 16px 0 6px;
}

.eyebrow {
  color: #b54f35;
  font-size: 13px;
  font-weight: 800;
  letter-spacing: 0;
  margin-bottom: 10px;
  text-transform: uppercase;
}

.card {
  background: white;
  border: 1px solid rgba(96, 76, 64, 0.12);
  border-radius: 8px;
  padding: 18px;
  box-shadow: 0 10px 30px rgba(60, 30, 20, 0.06);
}

.event-list {
  display: grid;
  gap: 12px;
}

.event-card {
  display: flex;
  gap: 14px;
  padding: 16px;
  color: inherit;
  text-decoration: none;
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid rgba(96, 76, 64, 0.12);
  border-radius: 8px;
  box-shadow: 0 10px 30px rgba(60, 30, 20, 0.06);
  transition: transform 160ms ease, border-color 160ms ease, box-shadow 160ms ease;
}

.event-card:hover {
  transform: translateY(-2px);
  border-color: rgba(181, 79, 53, 0.35);
  box-shadow: 0 16px 36px rgba(60, 30, 20, 0.1);
}

.event-card__date {
  flex: 0 0 92px;
  display: grid;
  align-content: start;
  gap: 6px;
  color: #695e58;
  font-size: 13px;
}

.event-card__date strong {
  color: #181614;
  font-size: 15px;
  line-height: 1.2;
}

.event-card__body {
  min-width: 0;
  flex: 1;
}

.event-card__topline {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}

.event-card h2 {
  margin: 0;
  font-size: 21px;
  line-height: 1.15;
}

.event-card p {
  margin: 10px 0 0;
  color: #695e58;
  line-height: 1.45;
}

.meta {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  color: #695e58;
}

.event-card__meta {
  display: grid;
  gap: 4px;
  margin-top: 8px;
  color: #695e58;
  font-size: 15px;
}

.pill {
  display: inline-flex;
  align-items: center;
  min-height: 26px;
  border-radius: 999px;
  padding: 4px 10px;
  background: var(--color-light-gold);
  color: var(--color-black);
  font-size: 13px;
  font-weight: 800;
}

.price {
  color: var(--color-muted);
  font-size: 14px;
  font-weight: 700;
  white-space: nowrap;
}

.price-badge {
  display: inline-flex;
  align-items: center;
  padding: 6px 10px;
  border-radius: 999px;
  background: rgba(0,0,0,0.06);
  color: var(--color-black);
  font-weight: 800;
  font-size: 13px;
}

.price-badge.free {
  background: var(--color-orange);
  color: white;
  box-shadow: 0 4px 10px rgba(233,91,0,0.12);
}

.button {
  display: inline-flex;
  justify-content: center;
  align-items: center;
  border: 0;
  border-radius: 999px;
  padding: 10px 16px;
  background: var(--color-orange);
  color: white;
  text-decoration: none;
  font-weight: 700;
  cursor: pointer;
}

.button.secondary {
  background: var(--color-off-white);
  color: var(--color-black);
}

.detail {
  display: grid;
  gap: 18px;
}

.detail-hero {
  margin-bottom: 0;
}

.detail-back {
  display: inline-flex;
  width: fit-content;
  align-items: center;
  min-height: 42px;
  padding: 0 14px;
  border-radius: 999px;
  border: 1px solid rgba(96, 76, 64, 0.14);
  background: rgba(255, 255, 255, 0.82);
  text-decoration: none;
  color: #473f3a;
  font-weight: 800;
}

.detail-summary {
  display: grid;
  gap: 16px;
}

.detail-summary__place {
  display: grid;
  gap: 6px;
  padding: 18px;
  border-radius: 14px;
  background: #181614;
  color: white;
}

.detail-summary__place span {
  color: rgba(255, 255, 255, 0.74);
  font-size: 13px;
  font-weight: 800;
  text-transform: uppercase;
}

.detail-summary__place strong {
  font-size: 28px;
  line-height: 1.05;
}

.detail-summary__facts {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.detail-fact {
  display: grid;
  gap: 4px;
  padding: 14px;
  border-radius: 14px;
  background: #fcf5ef;
}

.detail-fact span {
  color: #8a7469;
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
}

.detail-fact strong {
  font-size: 16px;
  line-height: 1.35;
}

.detail-fact p {
  margin: 0;
  color: #695e58;
  font-size: 14px;
  line-height: 1.35;
}

.detail-section h2,
.detail-cta h2 {
  margin: 0 0 8px;
  font-size: 22px;
}

.detail-section p,
.detail-cta p {
  margin: 0;
  color: #695e58;
  line-height: 1.45;
}

.detail-cta {
  display: grid;
  gap: 16px;
}

.detail-cta__button {
  width: 100%;
  min-height: 48px;
}

.detail-actions {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.flash-message {
  margin: 0 0 14px;
  padding: 12px 14px;
  border: 1px solid rgba(225, 125, 16, 0.12);
  border-radius: 12px;
  background: rgba(246, 182, 55, 0.08);
  color: var(--color-dark-gold);
  font-weight: 700;
}

.form {
  display: grid;
  gap: 14px;
}

.form-actions {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}

.required-note {
  margin: 0;
  color: #695e58;
  font-size: 14px;
  font-weight: 700;
}

.field {
  display: grid;
  gap: 6px;
}

label {
  font-weight: 700;
}

input, textarea, select {
  width: 100%;
  border: 1px solid #d8cbc5;
  border-radius: 12px;
  padding: 11px 12px;
  background: white;
}

textarea { min-height: 90px; }

.grid-two {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
}

.filters {
  display: flex;
  gap: 8px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}

.filter-button {
  border: 1px solid rgba(96, 76, 64, 0.14);
  border-radius: 999px;
  padding: 10px 14px;
  background: rgba(255, 255, 255, 0.72);
  color: #473f3a;
  font-weight: 800;
  cursor: pointer;
}

.filter-button.active {
  background: #181614;
  color: #fff;
  border-color: #181614;
}

.category-filter {
  display: grid;
  gap: 7px;
  margin-bottom: 18px;
}

.category-filter span {
  color: #695e58;
  font-size: 13px;
  font-weight: 800;
}

.empty-state {
  padding: 18px;
  border: 1px dashed rgba(96, 76, 64, 0.24);
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.62);
  color: #695e58;
}

.search-section {
  margin-bottom: 18px;
}

.search-input {
  width: 100%;
  padding: 12px 14px;
  border: 1px solid #d8cbc5;
  border-radius: 12px;
  font-size: 16px;
}

.search-input::placeholder {
  color: #9a8b82;
}

.event-date-group {
  margin-bottom: 28px;
}

.event-date-header {
  font-size: 18px;
  font-weight: 700;
  margin: 0 0 12px;
  color: #181614;
}

.status {
  margin-top: 10px;
  color: #695e58;
}

@media (max-width: 700px) {
  .topbar {
    align-items: center;
    flex-wrap: wrap;
    gap: 8px;
  }

  .brand {
    flex: 0 0 100%;
  }

  nav {
    flex: 1;
    justify-content: flex-end;
    gap: 6px;
  }

  .button-link {
    font-size: 13px;
    padding: 6px 8px;
  }

  .grid-two { grid-template-columns: 1fr; }
  .detail-summary__facts { grid-template-columns: 1fr; }
}

@media (max-width: 520px) {
  .container {
    padding-top: 22px;
  }

  .hero h1 {
    font-size: 36px;
  }

  .event-card {
    flex-direction: column;
    gap: 12px;
  }

  .event-card__date {
    display: flex;
    flex-basis: auto;
    justify-content: space-between;
    align-items: center;
  }

  .filters {
    gap: 6px;
  }

  .filter-button {
    font-size: 13px;
    padding: 8px 12px;
  }

  .form-actions {
    flex-direction: column;
  }

  .form-actions .button {
    width: 100%;
  }
}

