  margin-bottom: 18px;
}

.search-input {
  width: 100%;
  padding: 12px 14px;
  border: 1px solid #d8cbc5;
  border-radius: 12px;
  font-size: 16px;
}

.search-input::placeholder {
  color: #9a8b82;
}

.event-date-group {
  margin-bottom: 28px;
}

.event-date-header {
  font-size: 18px;
  font-weight: 700;
  margin: 0 0 12px;
  color: #181614;
}

.status {
  margin-top: 10px;
  color: #695e58;
}

@media (max-width: 700px) {
  .topbar {
    align-items: center;
    flex-wrap: wrap;
    gap: 8px;
  }

  .brand {
    flex: 0 0 100%;
  }

  nav {
    flex: 1;
    justify-content: flex-end;
    gap: 6px;
  }

  .button-link {
    font-size: 13px;
    padding: 6px 8px;
  }

  .grid-two { grid-template-columns: 1fr; }
  .detail-summary__facts { grid-template-columns: 1fr; }
}

@media (max-width: 520px) {
  .container {
    padding-top: 22px;
  }

  .hero h1 {
    font-size: 36px;
  }

  .event-card {
    flex-direction: column;
    gap: 12px;
  }

  .event-card__date {
    display: flex;
    flex-basis: auto;
    justify-content: space-between;
    align-items: center;
  }

  .filters {
    gap: 6px;
  }

  .filter-button {
    font-size: 13px;
    padding: 8px 12px;
  }

  .form-actions {
    flex-direction: column;
  }

  .form-actions .button {
    width: 100%;
  }
}
